#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <dirent.h>
#include <sys/stat.h>
#include <unistd.h>
#include <time.h>

#define MINIGIT_DIR ".minigit"
#define INDEX_FILE ".minigit/index"
#define COMMIT_DIR ".minigit/commits"
#define MAX_FILES 100
#define HASH_LEN 40
#define MSG_LEN 100

char tracked_files[MAX_FILES][256];
int file_count = 0;

void init() {
    mkdir(MINIGIT_DIR, 0755);
    mkdir(COMMIT_DIR, 0755);
    FILE *index = fopen(INDEX_FILE, "w");
    fclose(index);
    printf("Initialized minigit repository\n");
}

void add(const char *filename) {
    FILE *index = fopen(INDEX_FILE, "a");
    fprintf(index, "%s\n", filename);
    fclose(index);
    printf("Added %s\n", filename);
}

void load_index() {
    FILE *index = fopen(INDEX_FILE, "r");
    if (!index) return;
    file_count = 0;
    while (fscanf(index, "%255s", tracked_files[file_count]) == 1) {
        file_count++;
    }
    fclose(index);
}

void save_commit(const char *hash, const char *msg) {
    char path[512];
    snprintf(path, sizeof(path), "%s/%s", COMMIT_DIR, hash);
    FILE *f = fopen(path, "w");
    fprintf(f, "%s\n", msg);
    for (int i = 0; i < file_count; i++) {
        fprintf(f, "%s\n", tracked_files[i]);
        snprintf(path, sizeof(path), "cp %s %s/%s 2>/dev/null || true", tracked_files[i], COMMIT_DIR, hash);
        char cmd[1024];
        snprintf(cmd, sizeof(cmd), "mkdir -p %s/%s && cp %s %s/%s/%s 2>/dev/null || true", COMMIT_DIR, hash, tracked_files[i], COMMIT_DIR, hash, tracked_files[i]);
        system(cmd);
    }
    fclose(f);
}

void commit(const char *msg) {
    load_index();
    char hash[HASH_LEN + 1];
    snprintf(hash, sizeof(hash), "%ld", (long)time(NULL));
    save_commit(hash, msg);
    printf("Committed with hash %s\n", hash);
}

void log_commits() {
    struct dirent *entry;
    DIR *dp = opendir(COMMIT_DIR);
    if (!dp) return;
    while ((entry = readdir(dp))) {
        if (entry->d_name[0] == '.') continue;
        char path[512];
        snprintf(path, sizeof(path), "%s/%s", COMMIT_DIR, entry->d_name);
        FILE *f = fopen(path, "r");
        if (!f) continue;
        char msg[MSG_LEN];
        if (fgets(msg, sizeof(msg), f)) {
            msg[strcspn(msg, "\n")] = 0;
            printf("commit %s\n", entry->d_name);
            printf("Message: %s\n", msg);
        }
        fclose(f);
    }
    closedir(dp);
}

void checkout(const char *hash) {
    char path[512];
    snprintf(path, sizeof(path), "%s/%s", COMMIT_DIR, hash);
    struct stat st;
    if (stat(path, &st) != 0) {
        printf("Commit not found\n");
        return;
    }
    char cmd[1024];
    snprintf(cmd, sizeof(cmd), "cd %s/%s && find . -type f -exec cp --parents {} /tmp/minigit-test/ \\; 2>/dev/null || true", COMMIT_DIR, hash);
    system(cmd);
    printf("Checked out %s\n", hash);
}

void reset(const char *hash) {
    char path[512];
    snprintf(path, sizeof(path), "%s/%s", COMMIT_DIR, hash);
    struct stat st;
    if (stat(path, &st) != 0) {
        printf("Commit not found\n");
        return;
    }
    char cmd[1024];
    snprintf(cmd, sizeof(cmd), "rm -rf %s && mkdir %s", COMMIT_DIR, COMMIT_DIR);
    system(cmd);
    snprintf(cmd, sizeof(cmd), "cp -r %s %s/", path, COMMIT_DIR);
    system(cmd);
    printf("Reset to %s\n", hash);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        printf("Usage: minigit <command> [args]\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        init();
    } else if (strcmp(argv[1], "add") == 0 && argc > 2) {
        for (int i = 2; i < argc; i++) {
            add(argv[i]);
        }
    } else if (strcmp(argv[1], "commit") == 0 && argc > 3 && strcmp(argv[2], "-m") == 0) {
        commit(argv[3]);
    } else if (strcmp(argv[1], "log") == 0) {
        log_commits();
    } else if (strcmp(argv[1], "checkout") == 0 && argc > 2) {
        checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0 && argc > 2) {
        reset(argv[2]);
    } else {
        printf("Unknown command\n");
        return 1;
    }
    return 0;
}
